const stdout = $input.item.json.stdout || '';
const stderr = $input.item.json.stderr || '';

// Fail if dbt pipeline script crashed
if (stderr.includes('Traceback') || stdout.includes('Error') && !stdout.includes('WARN')) {
  throw new Error(`run_dbt_pipeline.sh failed:\nSTDOUT: ${stdout.slice(-1000)}\nSTDERR: ${stderr.slice(-500)}`);
}

// Check dbt run passed all 24 models
const runMatch = stdout.match(/Done\. PASS=(\d+).*TOTAL=(\d+).*\n.*Finished running/);
const runPassed = stdout.includes('PASS=24') || stdout.includes('Completed successfully');
if (!runPassed) {
  throw new Error(`dbt run did not complete successfully:\n${stdout.slice(-1000)}`);
}

// Check dbt test passed all 74 tests
const testPassed = stdout.includes('PASS=74');
if (!testPassed) {
  throw new Error(`dbt test did not pass all 74 tests:\n${stdout.slice(-1000)}`);
}

// Extract row counts from export step for logging
const exportMatch = stdout.match(/Done\. (\d+) rows written to DuckDB/);
const exportRows = exportMatch ? exportMatch[1] : 'unknown';

return [{ json: {
  success: true,
  export_rows: exportRows,
  dbt_run: 'PASS=24',
  dbt_test: 'PASS=74',
  stdout: stdout.slice(-500)
} }];

const stdout = $input.item.json.stdout || '';
const exitCode = $input.item.json.exitCode ?? 0;

// Log the full comparison result
const passed = stdout.includes('RESULT: ✓ PASS');
const failed = stdout.includes('RESULT: ✗ FAIL');

// During parallel validation we log but do NOT throw on mismatch
// This lets the workflow complete so you can review results in n8n history
// Change to throw new Error(...) after cutover if you want hard failures
if (failed) {
  console.log('PARALLEL VALIDATION WARNING: Pipeline mismatch detected. Review output.');
  console.log(stdout);
}

return [{ json: {
  comparison_passed: passed,
  comparison_result: passed ? 'PASS' : 'FAIL — review n8n execution log',
  stdout: stdout
} }];

